    vault.add({ sessionId: 's1', type: 'wonder', content: 'C', intensity: 9, tags: [] });

    const wonders = vault.query({ types: ['wonder'] });
    expect(wonders).toHaveLength(2);
    expect(wonders.every(m => m.type === 'wonder')).toBe(true);
  });

